import React, { useState } from 'react';
import { ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Box,
  Button,
  CardActivity,
  DetailTransactionValue,
  Header,
  SeparatorHorizontal,
  TagLabel,
  Text,
} from '@semparar/design-system-app';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';
import type { PointsTransaction } from '../services/models/extract.model';
import { formatToCurrency } from '../utils/functions';
import {
  getDetailScreenTitle,
  getFormattedHighlightText,
  getFormattedPointsValue,
  getOrigin,
  getPurchaseTypeLabel,
  getTagSubType,
  getTransactionGainType,
  getVehicleInfo,
} from '../screens/PointsDetail/utils';
import { moment } from '../services/moment';

const MOCK_TAG_TRANSACTION: PointsTransaction = {
  id: 'tag-1',
  date: '2026-02-20T14:30:00Z',
  description: 'Pedágio Rodovia Anhanguera',
  type: 'CREDIT',
  amount: 150,
  currencyValue: 1.5,
  icon: 'icon-tag',
  details: {
    provider: 'Sem Parar',
    extraInfo: 'Pedagio',
    fields: [
      { label: 'Marca', value: 'Volkswagen' },
      { label: 'Modelo', value: 'Gol' },
      { label: 'Placa', value: 'ABC-1234' },
    ],
  },
  status: 'CONFIRMED',
};

const MOCK_CARD_TRANSACTION: PointsTransaction = {
  id: 'card-1',
  date: '2026-02-18T10:15:00Z',
  description: 'Compra via cartão',
  type: 'CREDIT',
  amount: 320,
  currencyValue: 45.9,
  icon: 'icon-credit-card',
  details: {
    provider: 'Loja XYZ',
    extraInfo: '',
    fields: [{ label: 'Origem', value: 'Cartão Sem Parar Mais' }],
  },
  status: 'CONFIRMED',
};

const MOCK_CASHBACK_CREDIT: PointsTransaction = {
  id: 'cashback-1',
  date: '2026-02-15T16:45:00Z',
  description: 'Cashback na fatura',
  type: 'CREDIT',
  amount: 500,
  currencyValue: 5.0,
  icon: 'icon-invoice',
  details: {
    provider: 'Cashback Sem Parar',
    extraInfo: '',
    fields: [],
  },
  status: 'CONFIRMED',
};

const MOCK_CASHBACK_RESCUE: PointsTransaction = {
  id: 'cashback-2',
  date: '2026-02-12T09:00:00Z',
  description: 'Desconto na fatura',
  type: 'RESCUE',
  amount: 1000,
  currencyValue: 10.0,
  icon: 'icon-invoice',
  details: {
    provider: 'Cashback Sem Parar',
    extraInfo: '',
    fields: [],
  },
  status: 'CONFIRMED',
};

const MOCK_EXPIRED: PointsTransaction = {
  id: 'expired-1',
  date: '2026-01-10T00:00:00Z',
  description: 'Pontos expirados',
  type: 'EXPIRED',
  amount: 800,
  currencyValue: 8.0,
  icon: 'icon-less',
  details: {
    provider: '',
    extraInfo: '',
    fields: [],
  },
  status: 'EXPIRED',
};

const MOCK_REFUNDED: PointsTransaction = {
  id: 'refunded-1',
  date: '2026-02-08T11:30:00Z',
  description: 'Estorno voucher abastecimento',
  type: 'REFUNDED',
  amount: 250,
  currencyValue: 2.5,
  icon: 'icon-transfer',
  details: {
    provider: 'Sem Parar',
    extraInfo: '',
    fields: [],
  },
  status: 'REFUNDED',
};

const TRANSACTIONS_MAP: Record<string, PointsTransaction> = {
  'Tag (Pedágio)': MOCK_TAG_TRANSACTION,
  'Card Purchase': MOCK_CARD_TRANSACTION,
  'Cashback Credit': MOCK_CASHBACK_CREDIT,
  'Cashback Rescue': MOCK_CASHBACK_RESCUE,
  Expired: MOCK_EXPIRED,
  Refunded: MOCK_REFUNDED,
};

function Divider() {
  return (
    <SeparatorHorizontal
      borderWidth="smaller"
      borderColor="BRAND_COMPLEMENT_02"
      height={1}
      width="100%"
      mt="xxxxs"
    />
  );
}

function ReportProblemModal({ onClose }: { onClose: () => void }) {
  return (
    <Box
      bgColor="BRAND_COMPLEMENT_03"
      pd="innerSmall"
      style={{
        borderTopLeftRadius: 16,
        borderTopRightRadius: 16,
        borderWidth: 1,
        borderColor: '#e0e0e0',
      }}
    >
      <Box align="center" width="100%" mt="xxs">
        <Text
          type="paragraphXXXL"
          color="BRAND_COMPLEMENT_01"
          mb="xs"
          align="center"
        >
          Central de Atendimento
        </Text>
      </Box>

      <CardActivity
        mt="nano"
        icon="icon-contact"
        title="Capitais"
        description="4002 1552"
        iconRight="icon-next"
        showIcon
        showTagLabel={false}
        onPress={() => {}}
      />

      <CardActivity
        mt="nano"
        icon="icon-contact"
        title="Demais localidades"
        description="0800 015 0252"
        iconRight="icon-next"
        showIcon
        showTagLabel={false}
        onPress={() => {}}
      />

      <Text type="paragraphXS" color="INTENSE_COLOR_04" mt="xxxxs">
        *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das 9h
        às 17h.
      </Text>

      <Box align="center" width="100%" mt="xxxxs">
        <Text
          type="linkMDM"
          color="INTENSE_COLOR_05"
          onPress={onClose}
          align="center"
        >
          Fechar
        </Text>
      </Box>
    </Box>
  );
}

function PointsDetailStoryWrapper({
  transactionType = 'Tag (Pedágio)',
}: {
  transactionType?: string;
}) {
  const [showModal, setShowModal] = useState(false);
  const transaction = TRANSACTIONS_MAP[transactionType] || MOCK_TAG_TRANSACTION;

  const gainType = getTransactionGainType(transaction);
  const tagSubType = getTagSubType(transaction);
  const screenTitle = getDetailScreenTitle(gainType, transaction.type);
  const vehicleInfo = getVehicleInfo(transaction);
  const purchaseTypeLabel = getPurchaseTypeLabel(tagSubType);
  const origin = getOrigin(transaction);
  const formattedCurrencyValue = formatToCurrency(transaction.currencyValue);
  const formattedPointsValue = getFormattedPointsValue(
    transaction.amount,
    transaction.type,
  );
  const cardTitle = transaction.description || '';
  const highlightText = getFormattedHighlightText(
    transaction.date,
    gainType,
    moment,
  );

  const hasVehicleInfo = !!vehicleInfo && vehicleInfo !== '';
  const shouldShowOrigin = origin && !hasVehicleInfo;
  const hasPurchaseTypeLabel =
    !!purchaseTypeLabel && purchaseTypeLabel !== '';

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title={screenTitle}
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        <DetailTransactionValue
          icon={transaction.icon as never}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={
            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
              ? ('PLUS_COLOR_02' as const)
              : ('INTENSE_COLOR_05' as const)
          }
        />

        <Box ml="smaller" mr="smaller" mt="xxxxs" flex={1}>
          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
          />

          <Box mt="xxxs" flex={1} width="100%">
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
              Valor
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {formattedCurrencyValue}
            </Text>

            {gainType === 'TAG' && (
              <>
                <Divider />
                {shouldShowOrigin && (
                  <>
                    <Text
                      type="paragraphXL"
                      color="BRAND_COMPLEMENT_01"
                      mb="xxxxs"
                      mt="xxxxs"
                    >
                      Origem
                    </Text>
                    <Text type="paragraphMD" color="INTENSE_COLOR_03">
                      {origin}
                    </Text>
                    <Divider />
                  </>
                )}
                {hasVehicleInfo && (
                  <>
                    <Text
                      type="paragraphXL"
                      color="BRAND_COMPLEMENT_01"
                      mb="xxxxs"
                      mt="xxxxs"
                    >
                      Tag
                    </Text>
                    <Text type="paragraphMD" color="INTENSE_COLOR_03">
                      {vehicleInfo}
                    </Text>
                    <Divider />
                  </>
                )}
                {hasPurchaseTypeLabel && (
                  <>
                    <Text
                      type="paragraphXL"
                      color="BRAND_COMPLEMENT_01"
                      mb="xxxxs"
                      mt="xxxxs"
                    >
                      Tipo de compra
                    </Text>
                    <Text type="paragraphMD" color="INTENSE_COLOR_03">
                      {purchaseTypeLabel}
                    </Text>
                  </>
                )}
              </>
            )}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="secundaryLarge"
              text="Relatar Problema"
              onPress={() => setShowModal(true)}
            />
          </Box>
        </Box>

      </ScrollView>

      {showModal && (
        <ReportProblemModal onClose={() => setShowModal(false)} />
      )}
    </Box>
  );
}

const meta: Meta<typeof PointsDetailStoryWrapper> = {
  title: 'Screens/PointsDetail',
  component: PointsDetailStoryWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    transactionType: {
      control: { type: 'select' },
      options: Object.keys(TRANSACTIONS_MAP),
      description: 'Transaction type variant to display',
    },
  },
};

export default meta;
type Story = StoryObj<typeof PointsDetailStoryWrapper>;

export const TagTransaction: Story = {
  name: 'Tag Transaction (Pedágio)',
  args: { transactionType: 'Tag (Pedágio)' },
};

export const CardPurchase: Story = {
  name: 'Card Purchase',
  args: { transactionType: 'Card Purchase' },
};

export const CashbackCredit: Story = {
  name: 'Cashback Credit',
  args: { transactionType: 'Cashback Credit' },
};

export const CashbackRescue: Story = {
  name: 'Cashback Rescue (Usage)',
  args: { transactionType: 'Cashback Rescue' },
};

export const ExpiredTransaction: Story = {
  name: 'Expired Transaction',
  args: { transactionType: 'Expired' },
};

export const RefundedTransaction: Story = {
  name: 'Refunded Transaction',
  args: { transactionType: 'Refunded' },
};

